+            tracing::warn!(
+                event = "invoke_error",
+                connector_id = %connector_id,
+                operation = %operation,
+                correlation_id,
+                error = %err,
+                duration_ms = started_at.elapsed().as_millis() as u64,
+                "invoke request failed"
+            );
+            Err(map_host_error(err))
+        }
+    }
